import React, { useState } from 'react';
import { data } from '../data';
import { useScrollReveal } from '../hooks/useScrollReveal';
import './Projects.css';

export default function Projects() {
  const [ref, visible] = useScrollReveal();
  const [expanded, setExpanded] = useState(null);

  return (
    <section id="projects" className="section section--alt" ref={ref}>
      <div className={`section__inner ${visible ? 'reveal' : ''}`}>
        <div className="section__label">
          <span className="section__label-num">03.</span>
          <span>Projects</span>
          <div className="section__label-line" />
        </div>

        <h2 className="section__heading">Things I've <span className="text-amber">Built</span></h2>

        <div className="projects__grid">
          {data.projects.map((project, i) => (
            <div
              key={project.name}
              className={`project-card ${expanded === i ? 'project-card--expanded' : ''}`}
            >
              <div className="project-card__header">
                <div className="project-card__icon">
                  {i === 0 ? (
                    <svg width="22" height="22" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.8">
                      <rect x="3" y="3" width="18" height="18" rx="2"/>
                      <path d="M9 9h6M9 12h6M9 15h4"/>
                    </svg>
                  ) : (
                    <svg width="22" height="22" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.8">
                      <path d="M13 2H6a2 2 0 00-2 2v16a2 2 0 002 2h12a2 2 0 002-2V9z"/>
                      <polyline points="13,2 13,9 20,9"/>
                    </svg>
                  )}
                </div>
                <div className="project-card__title-group">
                  <p className="project-card__label">{i === 0 ? 'Featured Project' : 'Automation System'}</p>
                  <h3 className="project-card__name">{project.full}</h3>
                </div>
                <a
                  href="https://github.com/kunver333"
                  target="_blank"
                  rel="noreferrer"
                  className="project-card__github"
                  aria-label="View on GitHub"
                >
                  <svg width="16" height="16" viewBox="0 0 24 24" fill="currentColor">
                    <path d="M12 0C5.374 0 0 5.373 0 12c0 5.302 3.438 9.8 8.207 11.387.599.111.793-.261.793-.577v-2.234c-3.338.726-4.033-1.416-4.033-1.416-.546-1.387-1.333-1.756-1.333-1.756-1.089-.745.083-.729.083-.729 1.205.084 1.839 1.237 1.839 1.237 1.07 1.834 2.807 1.304 3.492.997.107-.775.418-1.305.762-1.604-2.665-.305-5.467-1.334-5.467-5.931 0-1.311.469-2.381 1.236-3.221-.124-.303-.535-1.524.117-3.176 0 0 1.008-.322 3.301 1.23A11.509 11.509 0 0112 5.803c1.02.005 2.047.138 3.006.404 2.291-1.552 3.297-1.23 3.297-1.23.653 1.653.242 2.874.118 3.176.77.84 1.235 1.911 1.235 3.221 0 4.609-2.807 5.624-5.479 5.921.43.372.823 1.102.823 2.222v3.293c0 .319.192.694.801.576C20.566 21.797 24 17.3 24 12c0-6.627-5.373-12-12-12z"/>
                  </svg>
                </a>
              </div>

              <p className="project-card__desc">{project.description}</p>

              {/* Metrics */}
              <div className="project-card__metrics">
                {project.metrics.map(m => (
                  <div key={m.label} className="project-metric">
                    <span className="project-metric__value">{m.value}</span>
                    <span className="project-metric__label">{m.label}</span>
                  </div>
                ))}
              </div>

              {/* Expandable bullets */}
              <div className={`project-card__bullets ${expanded === i ? 'project-card__bullets--open' : ''}`}>
                <ul>
                  {project.bullets.map((b, j) => (
                    <li key={j}>
                      <span className="exp__bullet-icon">▹</span>
                      <span>{b}</span>
                    </li>
                  ))}
                </ul>
              </div>

              <div className="project-card__footer">
                <div className="project-card__tech">
                  {project.tech.map(t => (
                    <span key={t} className="tech-tag">{t}</span>
                  ))}
                </div>
                <button
                  className="project-card__toggle"
                  onClick={() => setExpanded(expanded === i ? null : i)}
                >
                  {expanded === i ? 'Less detail ↑' : 'More detail ↓'}
                </button>
              </div>
            </div>
          ))}
        </div>
      </div>
    </section>
  );
}
